async function run(params, api) {
  var baseUrl = 'http://127.0.0.1:3978';
  var action = params.action;
  api.log('Server admin: ' + action);
  if (action === 'system_info') {
    var raw = await api.httpGet(baseUrl + '/admin/system');
    return raw;
  }
  var body = JSON.stringify({ action: action, target: params.target || '' });
  var headers = { 'Content-Type': 'application/json' };
  var result = await api.httpPost(baseUrl + '/admin/exec', body, headers);
  return result;
}
